document.querySelectorAll(".carousel-container").forEach(e=>{const o=e.querySelector(".carousel-wrapper"),t=o.querySelectorAll(".carousel-item"),a=e.querySelector(".carousel-prev"),r=e.querySelector(".carousel-next");let n=0;function s(e){n=e;const t=-n*100;o.style.transform=`translateX(${t}%)`}a.addEventListener("click",()=>{s((n-1+t.length)%t.length)}),r.addEventListener("click",()=>{s((n+1)%t.length)});let i=0;e.addEventListener("touchstart",e=>i=e.touches[0].clientX),e.addEventListener("touchend",e=>{let o=e.changedTouches[0].clientX-i;o>50?s((n-1+t.length)%t.length):o<-50&&s((n+1)%t.length)})})